import unittest

def add(a, b):
    return a + b

class TestAddFunction(unittest.TestCase):
    # --- Numeric Cases ---
    def test_positive_integers(self):
        self.assertEqual(add(1, 2), 3)

    def test_negative_integers(self):
        self.assertEqual(add(-1, -2), -3)

    def test_mixed_sign_integers(self):
        self.assertEqual(add(-1, 5), 4)

    def test_zeros(self):
        self.assertEqual(add(0, 0), 0)

    def test_floats(self):
        # Use assertAlmostEqual for floats to avoid precision issues
        self.assertAlmostEqual(add(0.1, 0.2), 0.3, places=7)

    def test_mixed_numeric(self):
        self.assertEqual(add(1, 2.5), 3.5)

    # --- Sequence Cases ---
    def test_strings(self):
        self.assertEqual(add("Hello ", "World"), "Hello World")

    def test_lists(self):
        self.assertEqual(add([1, 2], [3, 4]), [1, 2, 3, 4])

    def test_tuples(self):
        self.assertEqual(add((1, 2), (3, 4)), (1, 2, 3, 4))

    # --- Error Cases ---
    def test_type_mismatch(self):
        """Ensure that adding incompatible types raises a TypeError."""
        with self.assertRaises(TypeError):
            add(1, "2")

if __name__ == '__main__':
    unittest.main()
